using BgCommon.Script.Runtime.DotNet;namespace BgCommon.Script.Runtime.Compilation;/// <summary>/// 编译输入信息类，包含 <see cref="ICodeCompiler"/> 编译脚本所需的全部参数./// </summary>public class CompilationInput{    /// <summary>    /// Initializes a new instance of the <see cref="CompilationInput"/> class.    /// </summary>    /// <param name="targetFrameworkVersion">目标 .NET 框架版本.</param>    /// <param name="imageReferences">内存程序集镜像引用集合.</param>    /// <param name="references">程序集文件路径引用集合.</param>    /// <param name="usings">上下文命名空间.</param>    /// <param name="scriptGlobals">脚本全局变量.</param>    public CompilationInput(        DotNetFrameworkVersion targetFrameworkVersion,        HashSet<byte[]>? imageReferences = null,        HashSet<LibraryRef>? references = null,        HashSet<string>? usings = null,        ScriptGlobals? scriptGlobals = null)    {        this.Id = Guid.NewGuid();        this.TargetFrameworkVersion = targetFrameworkVersion;        this.ImageReferences = imageReferences ?? new();        this.References = references ?? new();        this.Usings = usings ?? new();        this.ScriptGlobals = scriptGlobals ?? new DefaultScriptGlobals();    }    /// <summary>    /// Gets 文档标识ID.    /// </summary>    public Guid Id { get; }    /// <summary>    /// Gets 源代码编译所需的内存程序集镜像集合.    /// </summary>    public HashSet<byte[]> ImageReferences { get; }    /// <summary>    /// Gets 源代码编译所需的程序集文件路径集合.    /// </summary>    public HashSet<LibraryRef> References { get; }    /// <summary>    /// Gets 源代码编译所需的命名空间的集合.    /// </summary>    public HashSet<string> Usings { get; }    /// <summary>    /// Gets 需要编译的源代码.    /// </summary>    public string Code { get; private set; } = string.Empty;    /// <summary>    /// Gets 编译生成的程序集名称.    /// </summary>    public string AssemblyName { get; private set; } = string.Empty;    /// <summary>    /// Gets 源代码的种类（如脚本或常规源文件）.    /// </summary>    public SourceCodeKind SourceCodeKind { get; private set; } = SourceCodeKind.Regular;    /// <summary>    /// Gets 脚本编译生成的程序集输出类型.    /// </summary>    /// <remarks>    /// 默认值为 <see cref="OutputKind.ConsoleApplication"/> 而非 <see cref="OutputKind.DynamicallyLinkedLibrary"/>，    /// 以便生成的程序集可以作为可执行文件运行.    /// 使用 <see cref="OutputKind.DynamicallyLinkedLibrary"/> 生成的程序集没有入口点，无法作为独立的外部进程执行.    /// </remarks>    public OutputKind OutputKind { get; private set; } = OutputKind.ConsoleApplication;    /// <summary>    /// Gets 脚本编译的目标 .NET 框架版本.    /// </summary>    public DotNetFrameworkVersion TargetFrameworkVersion { get; private set; }    /// <summary>    /// Gets 编译时使用的优化级别（Debug 或 Release）.    /// </summary>    public OptimizationLevel OptimizationLevel { get; private set; } = OptimizationLevel.Debug;    /// <summary>    /// Gets a value indicating whether 编译时是否包含 ASP.NET Core 程序集引用.    /// </summary>    public bool UseAspNet { get; private set; }    /// <summary>    /// Gets ScriptGlobals.    /// </summary>    public ScriptGlobals ScriptGlobals { get; private set; }    /// <summary>    /// 设置脚本内容.    /// </summary>    /// <param name="code">脚本内容.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetCode(string code)    {        this.Code = code;        return this;    }    /// <summary>    /// 设置编译生成的程序集名称.    /// </summary>    /// <param name="assemblyName">程序集名称字符串.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetAssemblyName(string assemblyName)    {        this.AssemblyName = assemblyName;        return this;    }    /// <summary>    /// 设置编译方式.    /// </summary>    /// <param name="sourceCodeKind">输出类型枚举值.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetSourceCodeKind(SourceCodeKind sourceCodeKind)    {        this.SourceCodeKind = sourceCodeKind;        return this;    }    /// <summary>    /// 设置编译的输出类型.    /// </summary>    /// <param name="outputKind">输出类型枚举值.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetOutputKind(OutputKind outputKind)    {        this.OutputKind = outputKind;        return this;    }    /// <summary>    /// 设置是否在编译中使用 ASP.NET 引用.    /// </summary>    /// <param name="useAspNet">是否启用的布尔值.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetUseAspNet(bool useAspNet = true)    {        // 设置 ASP.NET 使用状态        this.UseAspNet = useAspNet;        return this;    }    /// <summary>    /// 设置编译的优化级别.    /// </summary>    /// <param name="level">优化级别枚举值.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetOptimizationLevel(OptimizationLevel level)    {        // 设置代码优化级别        this.OptimizationLevel = level;        return this;    }    /// <summary>    /// 设置脚本全局变量.    /// </summary>    /// <param name="scriptGlobals">脚本全局共用变量实例.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput SetScriptGlobals(ScriptGlobals scriptGlobals)    {        ArgumentNullException.ThrowIfNull(scriptGlobals, nameof(scriptGlobals));        this.ScriptGlobals = scriptGlobals;        return this;    }    /// <summary>    /// 添加引用列表.    /// </summary>    /// <param name="libraryRefs">引用列表.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput AddReferences(params LibraryRef[] libraryRefs)    {        foreach (var libraryRef in libraryRefs.Select(s => s.Clone()))        {            this.References.Add(libraryRef);        }        return this;    }    /// <summary>    /// 设置编译的输出类型.    /// </summary>    /// <param name="usingList">上下文命名空间.</param>    /// <returns>当前编译输入实例.</returns>    public CompilationInput AddUings(params string[] usingList)    {        foreach (var usings in usingList.Select(s => s.Trim()))        {            this.Usings.Add(usings);        }        return this;    }    public CompilationInput ClearUsings()    {        this.Usings.Clear();        return this;    }    public CompilationInput ClearReferences()    {        this.References.Clear();        return this;    }}